export type MigrationCutoverDisposition=
  | {constructId:string;kind:'exact-equivalence';targetPaths:string[];proof:string}
  | {constructId:string;kind:'retained-dialect';targetPaths:string[];dialect:string;roundTrip:boolean;proof?:string}
  | {constructId:string;kind:'typed-loss';targetPaths:string[];loss:{code:string;effect:string;authorizationRequired:boolean};proof?:string}
  | {constructId:string;kind:'rejection';reason:{code:string;message:string};proof?:string;targetPaths?:string[]};
export interface SignedTypedLossAuthorization{statement:{id:string;sourceDigest:string;constructId:string;lossCode:string;approvedBy:string;expiresAt:string;nonce:string};digest:string;signer:string;algorithm:string;signature:string}
export function signTypedLossAuthorization(statement:SignedTypedLossAuthorization['statement'],signer:{signer:string;algorithm:string;sign(digest:string):string}):SignedTypedLossAuthorization{const authorizationDigest=hash(statement);return{statement:clone(statement),digest:authorizationDigest,signer:signer.signer,algorithm:signer.algorithm,signature:signer.sign(authorizationDigest)};}
type LegacyV1Schema='autonomy.ir.v1';
export interface LegacyV1Installation{schema:LegacyV1Schema;version:string;installationId:string;profile:string;constructs:Array<{id:string;kind:string;value:unknown}>;publicCommands:string[];ownedState:any}
export interface MigrationCorpusEntry{id:string;source:LegacyV1Installation;declaredObservations:Array<{id:string;projection:string}>}
export interface DiscoveredMigrationCorpusEntry extends MigrationCorpusEntry{v1Ir:AutonomyIR;provenance:{sourcePath:string;sourceDigest:string}}
export interface DiscoveredV2Compiler{id:string;generation:'v2';digest:string;sourceDigests:Record<string,string>;catalogDigest:string;runtimeAbi:'autonomy.ir.v1'}
export interface LegacyMigrationResult{organization:OrganizationIR;frontend:{sourceSchema:string;sourceVersion:string;frontendVersion:string};ledger:MigrationCutoverDisposition[];retainedDialects:Record<string,unknown>}
type Drift='drop-command'|'change-owned-state'|'reroute-issue'|'weaken-review'|'extra-effect';
interface ObservationResult{id:string;status:'equivalent'|'different';witness?:string}
type ObservationEvaluation=Omit<ObservationResult,'id'>;
interface CompilerExecutionEvidence{compilerDigest:string;invocationDigest:string;certificateDigest?:string;provenanceChainDigest?:string}
export interface MigrationCorpusReport{profiles:Array<{id:string;v1InstallationDigest:string;v2InstallationDigest:string;v1ExecutionEvidenceDigest?:string;v2ExecutionEvidenceDigest?:string;observations:ObservationResult[]}>;equivalent:boolean;untriagedResiduals:string[];corpusDigest:string;digest:string;compilerProvenance:{v1:{digest:string;executionEvidenceDigests?:string[]};v2:{digest:string;executionEvidenceDigests?:string[]}};assertReadyForShadow():void}

const hash=(value:unknown)=>`sha256:${createHash('sha256').update(canonicalSemanticJson(value)).digest('hex')}`;
const supportedProofs=new Set(['normalized-equality','trace-bisimulation','decision-table-equality']);
const clone=<T>(value:T):T=>structuredClone(value);
const sourceHash=(value:unknown)=>`sha256:${createHash('sha256').update(JSON.stringify(value)).digest('hex')}`;
const portableId=(prefix:string,value:string)=>`${prefix}-${createHash('sha256').update(value).digest('hex').slice(0,16)}`;
const valueAt=(root:unknown,path:string)=>path.split('.').reduce<unknown>((value,key)=>value&&typeof value==='object'&&Object.prototype.hasOwnProperty.call(value,key)?(value as Record<string,unknown>)[key]:undefined,root);
const resolves=(root:unknown,path:string)=>valueAt(root,path)!==undefined;
const compileNativeIR=async(ir:AutonomyIR)=>{const outputs:Record<string,CompileOutput>={};for(const target of ir.targets){if(target==='local')outputs[target]=(await import('@open-autonomy/substrate-local')).compileLocal(ir);else if(target==='gh-actions')outputs[target]=(await import('@open-autonomy/substrate-github')).compileGithub(ir);}return outputs;};
const materializedInstallation=async(outputs:Record<string,CompileOutput>,profileRoot:string)=>Object.fromEntries(await Promise.all(Object.entries(outputs).map(async([target,output])=>{const files:Record<string,string>={};for(const [path,content] of Object.entries(output.generated))files[path]=sourceHash(content);for(const copy of output.copies)files[copy.to]=`sha256:${createHash('sha256').update(await readFile(join(profileRoot,copy.from))).digest('hex')}`;return[target,Object.fromEntries(Object.entries(files).sort())];})));
export const MIGRATION_PUBLIC_COMMANDS=['status','pause','resume','cancel','logs'] as const;
