const legacyStateProbe=(seed:any)=>{const state=clone(seed);state.issues??=[];state.issues.push({id:'migration-probe'});state.checkpoints={sequence:2};return state;};
const v2StateProbe=(seed:any)=>{const ready={assertReadyForShadow(){},corpusDigest:'sha256:probe'} as MigrationCorpusReport;return createMigrationCutoverController({corpusReport:ready,initialRuntime:'v1',ownedState:seed,publicCommands:[...MIGRATION_PUBLIC_COMMANDS]}).recordOwnedMutation({id:'probe:issue',operation:'issue-created',value:{id:'migration-probe'}}).recordOwnedMutation({id:'probe:checkpoint',operation:'checkpoint-updated',value:{sequence:2}}).state.ownedState;};
const behaviorObservation=(outputs:Record<string,CompileOutput>)=>Object.fromEntries(Object.entries(outputs).map(([target,output])=>{const manifest=output.generated['.open-autonomy/autonomy.yml'];if(!manifest)return[target,null];const parsed=parseYaml(manifest) as any;return[target,{agents:Object.fromEntries(Object.entries(parsed.agents??{}).map(([id,value]:[string,any])=>[id,{kind:value.kind??'agent',triggers:value.triggers,params:value.params,review:value.review,capabilities:value.capabilities}])),policy:parsed.policy}];}));
