const installationObservation=(value:Record<string,unknown>)=>Object.fromEntries(Object.entries(value).filter(([key])=>!['publicCommands','commandSurface','rawOutputs','organization','certificate','ownedState','behavior','compilerEvidence'].includes(key)));
const discoveredObservationEvaluators:Record<string,(input:{v1:any;v2:any})=>ObservationEvaluation>={
  'installation.files':({v1,v2})=>canonicalSemanticJson(installationObservation(v1))===canonicalSemanticJson(installationObservation(v2))?{status:'equivalent'}:{status:'different',witness:'emitted installation differs'},
  'runtime.commandSurface':({v1,v2})=>canonicalSemanticJson(v1.commandSurface)===canonicalSemanticJson(v2.commandSurface)?{status:'equivalent'}:{status:'different',witness:'installed runtime command surface differs'},
  'state.owned':({v1,v2})=>canonicalSemanticJson(v1.ownedState)===canonicalSemanticJson(v2.ownedState)?{status:'equivalent'}:{status:'different',witness:'owned state differs'},
  'behavior.routing-review-effects':({v1,v2})=>canonicalSemanticJson(v1.behavior)===canonicalSemanticJson(v2.behavior)?{status:'equivalent'}:{status:'different',witness:'routing, review, trigger, authority, or policy behavior differs'},
};

