  const actors=Object.fromEntries(Object.entries(entry.v1Ir.agents).map(([id,agent])=>[id,{kind:agent.kind==='human'?'human':'agent',behaviors:[id],capabilities:agent.capabilities.map(capability=>({capability:capabilityIds.get(capability)!})),activation:agent.triggers.map(trigger=>'cron'in trigger?{kind:'schedule',expression:trigger.cron}:'event'in trigger?{kind:'event',eventType:trigger.event}:{kind:'manual'}),extensions:{v1Projection:{kind:agent.kind,triggers:agent.triggers,timeout:agent.timeout,result:agent.result,prelaunch:agent.prelaunch}}}]));
  const behaviors=Object.fromEntries(Object.entries(entry.v1Ir.agents).map(([id,agent])=>[id,{kind:isScript(agent.behavior)?'program':'skill',source:{uri:agent.behavior}}]));
  const capabilities=Object.fromEntries([...capabilityIds].map(([source,id])=>[id,{resourceKinds:[source.split(':')[0]??source],actions:[source.split(':')[1]?.split('@')[0]??'use'],extensions:{v1Capability:source}}]))
  const relations=Object.fromEntries(Object.entries(entry.v1Ir.agents).filter(([,agent])=>agent.review).map(([id,agent])=>[`review-${id}`,{kind:'reviews',from:agent.review!,to:id}]));
