  const dialect=(organization.types!['v1-installation']!.extensions as any).projection,policyProjection=organization.policies!['v1-profile']!.rule as unknown as AutonomyIR['policy'],actorProjection=Object.fromEntries(Object.entries(organization.actors).map(([id,actor])=>{const retained=(actor.extensions as any)?.v1Projection??{},review=Object.values(organization.relations??{}).find(relation=>relation.kind==='reviews'&&relation.to===id)?.from;return[id,{capabilities:(actor.capabilities??[]).map(grant=>(organization.capabilities?.[grant.capability]?.extensions as any)?.v1Capability??grant.capability),triggers:clone(retained.triggers??[]),kind:retained.kind,timeout:retained.timeout,review,result:clone(retained.result),prelaunch:retained.prelaunch}];})),projected=lowerExecutionToV1(organization,fixed.execution,{targets:dialect.targets,codeHost:dialect.codeHost,policy:policyProjection,resources:dialect.resources,documents:dialect.documents,actorProjection});if(!projected.output||!projected.certificate)throw new Error(`v2-to-v1 backend lowering failed: ${projected.errors.join('; ')}`);const loweredIr=projected.output;if(canonicalSemanticJson(loweredIr)!==canonicalSemanticJson(entry.v1Ir))throw new Error('v1 retained-dialect round-trip differs from source profile');
