export function deriveLegacyRemovalDecision(input:any):LegacyRemovalDecision{if(!input.artifacts||!input.verifier)throw new Error('signed removal artifacts and external verifier are required');const artifacts=Object.values(input.artifacts) as Array<{digest:string;signature:string}>;if(artifacts.some(artifact=>!input.verifier.verify(artifact)))throw new Error('removal artifact verification failed');const derived=input.verifier.deriveCriteria(input.artifacts);if(!derived?.criteria||typeof derived.criteria!=='object')throw new Error('removal verifier must derive the closed criteria record');const criteria=clone(derived.criteria) as Record<string,boolean>,assessment=assessLegacyRemoval(criteria),digest=hash({artifacts:input.artifacts,criteria,assessment,verifier:'external'});return{removable:assessment.removable&&!(derived.errors?.length),criteria,evidenceDigest:digest,digest};}
export function executeLegacyRemoval(decision:LegacyRemovalDecision,input:any){if(!decision.removable||!input.legacyRuntimeDigest||!input.authorization||!input.tombstoneStore||!input.authorizationTrust)throw new Error('durable authorized legacy removal inputs are required');if(input.authorization.decisionDigest!==decision.digest||!input.authorizationTrust.verify(input.authorization))throw new Error('decision authorization is forged');const tombstone={legacyRuntimeDigest:input.legacyRuntimeDigest,decisionDigest:decision.digest,authorization:input.authorization};if(!input.tombstoneStore.putIfAbsent(input.legacyRuntimeDigest,tombstone))throw new Error('legacy runtime already has irreversible tombstone');return{status:'removed' as const,...tombstone};}
export function proveV2DogfoodAdoption(proof:any,external?:{verifyR8LiveInstance(binding:unknown):any;canonical?:{repository:string;installation:string;sourceDigest:string;organizationDigest:string;expectedBundleDigest:string};trustedV2?:{compilerDigests:string[];runtimeDigests:string[]};verifyObservation(observation:any):{valid:boolean;errors:string[]}}){if(!external?.trustedV2||!external.canonical)throw new Error('external canonical, R8, observation, and trusted-v2 verifiers are required');const errors:string[]=[],canonical=external.canonical;if(proof?.schema!=='autonomy.dogfood-adoption-proof.v1'||proof.canonicalInstallation!==canonical.installation||proof.repository!==canonical.repository||proof.canonicalSourceDigest!==canonical.sourceDigest||proof.organizationDigest!==canonical.organizationDigest||proof.desiredBundleDigest!==canonical.expectedBundleDigest)errors.push('proof does not match the externally anchored canonical dogfood installation');if(proof.desiredBundleDigest!==proof.runningBundleDigest)errors.push('running bundle differs from desired bundle');if(proof.legacyBypassObserved)errors.push('legacy bypass was observed');const binding=proof.liveInstanceBinding,r8=external.verifyR8LiveInstance(binding),compilerDigest=r8.compilerDigest??proof.compiler?.digest,runtimeDigest=r8.runtimeDigest??proof.runtime?.digest,releaseDigest=r8.releaseDigest??binding?.releaseDigest;if(!r8.valid||binding?.bundleDigest!==proof.runningBundleDigest||r8.organizationDigest!==canonical.organizationDigest)errors.push(...(r8.errors??[]),'R8 live-instance bundle or organization binding is invalid');if(!external.trustedV2.compilerDigests.includes(compilerDigest)||!external.trustedV2.runtimeDigests.includes(runtimeDigest))errors.push('R8 compiler or runtime identity is not trusted v2');const observations=Array.isArray(proof.observations)?proof.observations:[];for(const observation of observations){const verified=external.verifyObservation(observation);if(!verified.valid)errors.push(...verified.errors,'observation verification failed');if(observation.subjectBundleDigest!==binding?.bundleDigest||observation.releaseDigest!==releaseDigest||observation.instanceId!==binding?.instanceId||observation.compilerDigest!==compilerDigest||observation.runtimeDigest!==runtimeDigest)errors.push('observation identity does not match verified live instance');}if(!observations.some((x:any)=>x.kind==='process')||!observations.some((x:any)=>x.kind==='effect'&&x.canonical===true&&String(x.command??'').trim()))errors.push('authenticated process and canonical effect observations are required');return{adopted:errors.length===0,errors:[...new Set(errors)],proofDigest:hash(JSON.parse(JSON.stringify(proof))),verifiedBy:'external-canonical-r8-and-observation-verifiers',compilerDigest,runtimeDigest};}
